import React from 'react';
import { Container } from 'react-bootstrap';

const HeroSection = () => {
  return (
    <div style={{ backgroundColor: 'var(--brand-dark)', color: 'white', padding: '6rem 0', textAlign: 'center' }}>
      <Container><h1>Bienvenido a Tecnotitlan</h1></Container>
    </div>
  );
};

export default HeroSection;
